function v(set_id: string, word: string, pos: string, mth: string, men: string, een: string, eth: string, idx: number): Vocabulary {
  return { id: `${set_id}-${idx}`, set_id, word, part_of_speech: pos, meaning_th: mth, meaning_en: men, example_en: een, example_th: eth, audio_url: null, order_index: idx, created_at: '' }
}

